function s(i){return String(i??"").replace(/\s+/g," ").trim().toLowerCase()}class a{name="Strategic Insight Graph Query";strategyForSector(t,e){return t.filter(r=>s(r.sector)===s(e)).sort((r,o)=>o.succesratio-r.succesratio).slice(0,5)}interventionForProblem(t,e){return t.filter(r=>s(r.probleemtype)===s(e)).sort((r,o)=>o.succesratio-r.succesratio).slice(0,5)}failingCombinations(t){return t.filter(e=>e.succesratio<=.45).sort((e,c)=>e.succesratio-c.succesratio).slice(0,8)}}export{a as S};
